void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = vUv-.5;

vec3 ret1 = texture(sampler_main, vUv) +texture(sampler_main, 1-vUv)*0;


vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0,uTexSize.w);
float dx = GetPixel (vUv-hor) - GetPixel (vUv+hor);
float dy = GetPixel (vUv-ver) - GetPixel (vUv+ver);
vec2 dz = vec2 (dx,dy);

uv1 = .3*cos(uv1*2+1.7) -2*dz;;
vec3 dots = clamp01(.03/length(uv1));


ret1 = (-ret1/4) + 6*dots*(-0.08+ret1);

ret = ret1;

    vec2 texc = 0.4 + 0.6*ret.xy;
    ret = texture(sampler_rand00, texc) * lum(ret) * 3;



  fragColor = ret;
